import { Router } from "express";
import { RoomController } from "../controllers/room.controller.js";
import { authMiddleware } from "../middlewares/auth.middleware.js";
import { roleMiddleware } from "../middlewares/roleMiddleware.js";
import { upload } from "../middlewares/upload.middleware.js";
const router = Router();
const staffRoles = ["ADMIN", "MANAGER", "RECEPTION"];
router.use(authMiddleware);
router.get("/", roleMiddleware(staffRoles), RoomController.findAll);
router.get("/:id", roleMiddleware(staffRoles), RoomController.findById);
router.post("/", roleMiddleware(["ADMIN", "MANAGER"]), upload.single("image"), RoomController.create);
router.patch("/:id", roleMiddleware(["ADMIN", "MANAGER"]), RoomController.update);
router.patch("/:id/status", roleMiddleware(staffRoles), RoomController.changeStatus);
router.delete("/:id", roleMiddleware(["ADMIN"]), RoomController.delete);
router.patch("/:id/cleaning/start", roleMiddleware(staffRoles), RoomController.startCleaning);
router.patch("/:id/cleaning/finish", roleMiddleware(staffRoles), RoomController.finishCleaning);
router.patch("/:id/inspect", roleMiddleware(staffRoles), RoomController.inspect);
router.patch("/:id/maintenance/start", roleMiddleware(["ADMIN", "MANAGER"]), RoomController.startMaintenance);
router.patch("/:id/maintenance/finish", roleMiddleware(["ADMIN", "MANAGER"]), RoomController.finishMaintenance);
export default router;
